import { useState, useEffect, useCallback } from 'react'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Badge } from '@/components/ui/badge'
import { Progress } from '@/components/ui/progress'
import { Tag, Wrench } from 'lucide-react'
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Cell,
} from 'recharts'
import { DateRange } from '@/components/DateRangeFilter'

interface CategoryStat {
  nome: string
  total: number
  percentual: number
}

interface CategoryDistributionCardProps {
  dateRange: DateRange
}

const COLORS_PARADA = [
  'hsl(var(--primary))',
  'hsl(210, 70%, 55%)',
  'hsl(190, 60%, 50%)',
  'hsl(170, 50%, 45%)',
  'hsl(150, 45%, 45%)',
  'hsl(130, 40%, 50%)',
]

const COLORS_PROBLEMA = [
  'hsl(25, 85%, 55%)',
  'hsl(35, 80%, 50%)',
  'hsl(45, 75%, 48%)',
  'hsl(55, 65%, 45%)',
  'hsl(15, 70%, 50%)',
  'hsl(5, 60%, 50%)',
]

export function CategoryDistributionCard({ dateRange }: CategoryDistributionCardProps) {
  const { profile, isAdminKraflo } = useAuth()
  const [categoriasParada, setCategoriasParada] = useState<CategoryStat[]>([])
  const [categoriasProblema, setCategoriasProblema] = useState<CategoryStat[]>([])
  const [totalOS, setTotalOS] = useState(0)
  const [semCategoria, setSemCategoria] = useState({ parada: 0, problema: 0 })
  const [isLoading, setIsLoading] = useState(true)

  const loadCategoryData = useCallback(async () => {
    try {
      setIsLoading(true)

      let query = supabase
        .from('ordens_de_servico')
        .select('categoria_parada_id, categoria_problema_id')
        .gte('data_abertura', dateRange.from.toISOString())
        .lte('data_abertura', dateRange.to.toISOString())

      if (!isAdminKraflo && profile?.empresa_id) {
        query = query.eq('empresa_id', profile.empresa_id)
      }

      const { data: osData, error } = await query

      if (error) throw error
      if (!osData || osData.length === 0) {
        setCategoriasParada([])
        setCategoriasProblema([])
        setTotalOS(0)
        return
      }

      setTotalOS(osData.length)

      // Contar por categoria de parada
      const paradaIds = osData
        .map((os) => os.categoria_parada_id)
        .filter(Boolean) as string[]
      const problemaIds = osData
        .map((os) => os.categoria_problema_id)
        .filter(Boolean) as string[]

      setSemCategoria({
        parada: osData.length - paradaIds.length,
        problema: osData.length - problemaIds.length,
      })

      // Buscar nomes das categorias
      if (paradaIds.length > 0) {
        const paradaCount = new Map<string, number>()
        paradaIds.forEach((id) => paradaCount.set(id, (paradaCount.get(id) || 0) + 1))

        const uniqueIds = [...new Set(paradaIds)]
        const { data: catParada } = await supabase
          .from('categorias_parada')
          .select('id, nome')
          .in('id', uniqueIds)

        if (catParada) {
          const stats: CategoryStat[] = catParada
            .map((cat) => ({
              nome: cat.nome,
              total: paradaCount.get(cat.id) || 0,
              percentual: Math.round(((paradaCount.get(cat.id) || 0) / osData.length) * 100),
            }))
            .sort((a, b) => b.total - a.total)
          setCategoriasParada(stats)
        }
      } else {
        setCategoriasParada([])
      }

      if (problemaIds.length > 0) {
        const problemaCount = new Map<string, number>()
        problemaIds.forEach((id) => problemaCount.set(id, (problemaCount.get(id) || 0) + 1))

        const uniqueIds = [...new Set(problemaIds)]
        const { data: catProblema } = await supabase
          .from('categorias_problema')
          .select('id, nome')
          .in('id', uniqueIds)

        if (catProblema) {
          const stats: CategoryStat[] = catProblema
            .map((cat) => ({
              nome: cat.nome,
              total: problemaCount.get(cat.id) || 0,
              percentual: Math.round(((problemaCount.get(cat.id) || 0) / osData.length) * 100),
            }))
            .sort((a, b) => b.total - a.total)
          setCategoriasProblema(stats)
        }
      } else {
        setCategoriasProblema([])
      }
    } catch (error) {
      console.error('Error loading category data:', error)
    } finally {
      setIsLoading(false)
    }
  }, [profile, isAdminKraflo, dateRange])

  useEffect(() => {
    loadCategoryData()
  }, [loadCategoryData])

  const renderBarChart = (data: CategoryStat[], colors: string[]) => {
    if (data.length === 0) {
      return (
        <div className="text-center py-8 text-muted-foreground text-sm">
          Nenhuma OS categorizada neste período
        </div>
      )
    }

    return (
      <ResponsiveContainer width="100%" height={220}>
        <BarChart data={data} layout="vertical" margin={{ left: 10, right: 20, top: 5, bottom: 5 }}>
          <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" horizontal={false} />
          <XAxis type="number" tick={{ fontSize: 11, fill: 'hsl(var(--muted-foreground))' }} />
          <YAxis
            type="category"
            dataKey="nome"
            width={130}
            tick={{ fontSize: 11, fill: 'hsl(var(--muted-foreground))' }}
          />
          <Tooltip
            contentStyle={{
              backgroundColor: 'hsl(var(--card))',
              border: '1px solid hsl(var(--border))',
              borderRadius: '8px',
              fontSize: '12px',
            }}
            formatter={(value: number, _name: string, props: any) => [
              `${value} OS (${props.payload.percentual}%)`,
              'Total',
            ]}
          />
          <Bar dataKey="total" radius={[0, 4, 4, 0]} maxBarSize={28}>
            {data.map((_entry, index) => (
              <Cell key={`cell-${index}`} fill={colors[index % colors.length]} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    )
  }

  const renderProgressList = (data: CategoryStat[], colors: string[]) => {
    if (data.length === 0) return null

    return (
      <div className="space-y-3 mt-4">
        {data.map((cat, index) => (
          <div key={cat.nome}>
            <div className="flex items-center justify-between mb-1">
              <span className="text-sm font-medium text-foreground">{cat.nome}</span>
              <span className="text-sm text-muted-foreground font-mono">
                {cat.total} ({cat.percentual}%)
              </span>
            </div>
            <Progress
              value={cat.percentual}
              className="h-2"
              style={{
                ['--progress-color' as any]: colors[index % colors.length],
              }}
            />
          </div>
        ))}
      </div>
    )
  }

  if (isLoading) {
    return (
      <Card className="bg-card border-border">
        <CardContent className="p-6">
          <div className="animate-pulse space-y-4">
            <div className="h-4 bg-muted rounded w-1/3" />
            <div className="h-48 bg-muted rounded" />
          </div>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card className="bg-card border-border">
      <CardHeader className="pb-3">
        <CardTitle className="font-mono text-lg flex items-center gap-2">
          <Tag className="h-5 w-5 text-primary" />
          Distribuição por Categorias
        </CardTitle>
        <CardDescription>
          Análise de {totalOS} OS por motivo de parada e causa raiz
        </CardDescription>
      </CardHeader>
      <CardContent>
        <Tabs defaultValue="parada" className="w-full">
          <TabsList className="grid w-full grid-cols-2 mb-4">
            <TabsTrigger value="parada" className="text-xs sm:text-sm">
              🔴 Motivo de Parada
            </TabsTrigger>
            <TabsTrigger value="problema" className="text-xs sm:text-sm">
              🔧 Causa Raiz
            </TabsTrigger>
          </TabsList>

          <TabsContent value="parada">
            {renderBarChart(categoriasParada, COLORS_PARADA)}
            {semCategoria.parada > 0 && (
              <div className="mt-3 flex items-center gap-2">
                <Badge variant="outline" className="text-xs text-muted-foreground">
                  {semCategoria.parada} OS sem categoria ({Math.round((semCategoria.parada / totalOS) * 100)}%)
                </Badge>
              </div>
            )}
          </TabsContent>

          <TabsContent value="problema">
            {renderBarChart(categoriasProblema, COLORS_PROBLEMA)}
            {semCategoria.problema > 0 && (
              <div className="mt-3 flex items-center gap-2">
                <Badge variant="outline" className="text-xs text-muted-foreground">
                  {semCategoria.problema} OS sem causa raiz ({Math.round((semCategoria.problema / totalOS) * 100)}%)
                </Badge>
              </div>
            )}
          </TabsContent>
        </Tabs>
      </CardContent>
    </Card>
  )
}

import { useState, useEffect, useCallback, useMemo } from 'react'
import { useForm, Controller, useWatch } from 'react-hook-form'
import { zodResolver } from '@hookform/resolvers/zod'
import * as z from 'zod'
import { osFormSchema, OSFormData } from '@/lib/validation-schemas'
import { handleError } from '@/lib/error-handler'
import { supabase } from '@/integrations/supabase/client'
import { useAuth } from '@/hooks/useAuth'
import { useOSCategories } from '@/hooks/useOSCategories'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { Label } from '@/components/ui/label'
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select'
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from '@/components/ui/dialog'
import { toast } from '@/components/ui/sonner'
import { Loader2, X, Image as ImageIcon } from 'lucide-react'
import { ReincidenciaAlert } from '@/components/ReincidenciaAlert'



interface Tecnico {
  id_telegram: number
  nome_completo: string
}

interface OSFormProps {
  open: boolean
  onClose: () => void
  onSuccess: () => void
  editingOS?: {
    id: number
    equipamento_nome: string
    equipamento_tag?: string | null
    localizacao?: string | null
    tipo_manutencao?: string | null
    prioridade?: string | null
    descricao_problema?: string | null
    diagnostico_solucao?: string | null
    notas_finais?: string | null
    tecnico_id: number
    empresa_id: string
    status_os: string
    url_foto?: string | null
  }
}

interface ReincidenciaData {
  encontrou: boolean
  total_recentes: number
  dias_limite?: number
  ultima_os?: {
    id: number
    descricao_problema: string | null
    diagnostico_solucao: string | null
    data_fechamento: string
    tecnico_id: number
    tecnico_nome: string | null
    dias_desde_fechamento: number
  }
}

function FormReincidenciaAlert({ control, data }: { control: any; data: ReincidenciaData | null }) {
  const tag = useWatch({ control, name: 'equipamento_tag' })
  if (!data?.encontrou) return null
  return <ReincidenciaAlert data={data} tag={tag || ''} />
}

export function OSForm({ open, onClose, onSuccess, editingOS }: OSFormProps) {
  const { profile, isAdminKraflo } = useAuth()
  const [isLoading, setIsLoading] = useState(false)
  const [tecnicos, setTecnicos] = useState<Tecnico[]>([])
  const [selectedTecnico, setSelectedTecnico] = useState<string>('')
  const [status, setStatus] = useState<
    | 'Aberta'
    | 'Em manutenção'
    | 'Fechada'
    | 'Liberado para produção'
    | 'Não liberado'
  >('Aberta')
  const [foto, setFoto] = useState<File | null>(null)
  const [fotoPreview, setFotoPreview] = useState<string | null>(null)

  // Categoria de parada
  const [categoriaParadaId, setCategoriaParadaId] = useState('')
  const [subcategoriaParadaId, setSubcategoriaParadaId] = useState('')
  const { categoriasParada, subcategorias } = useOSCategories()

  // Reincidência
  const [reincidenciaData, setReincidenciaData] = useState<ReincidenciaData | null>(null)
  const [checkingReincidencia, setCheckingReincidencia] = useState(false)

  const subcategoriasFiltradasParada = useMemo(() => {
    if (!categoriaParadaId) return []
    return subcategorias.filter(
      (s) => s.categoria_id === categoriaParadaId && s.tipo_categoria === 'parada'
    )
  }, [categoriaParadaId, subcategorias])

  const handleFotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      setFoto(file)
      const reader = new FileReader()
      reader.onloadend = () => {
        setFotoPreview(reader.result as string)
      }
      reader.readAsDataURL(file)
    }
  }

  const removeFoto = () => {
    setFoto(null)
    setFotoPreview(null)
  }

  // Check reincidência when TAG changes
  const checkReincidencia = useCallback(async (tag: string) => {
    if (!tag || tag.length < 2 || !profile?.empresa_id) {
      setReincidenciaData(null)
      return
    }
    setCheckingReincidencia(true)
    try {
      const { data, error } = await supabase.rpc('fn_check_reincidencia', {
        p_empresa_id: profile.empresa_id,
        p_tag: tag.trim(),
        p_dias_limite: 60,
      })
      if (error) throw error
      setReincidenciaData(data as unknown as ReincidenciaData)
    } catch (error) {
      console.error('Erro ao verificar reincidência:', error)
      setReincidenciaData(null)
    } finally {
      setCheckingReincidencia(false)
    }
  }, [profile?.empresa_id])

  const {
    register,
    handleSubmit,
    formState: { errors },
    reset,
    setValue,
    control,
  } = useForm<OSFormData>({
    resolver: zodResolver(osFormSchema),
    defaultValues: {
      tipo_manutencao: undefined,
      prioridade: undefined,
    },
  })

  const loadTecnicos = useCallback(async () => {
    try {
      let query = supabase.from('tecnicos').select('id_telegram, nome_completo')

      if (!isAdminKraflo && profile?.empresa_id) {
        query = query.eq('empresa_id', profile.empresa_id)
      }

      const { data, error } = await query
      if (error) throw error
      setTecnicos(data || [])

      if (data && data.length > 0 && !editingOS) {
        setSelectedTecnico(String(data[0].id_telegram))
      }
    } catch (error) {
      console.error('Error loading tecnicos:', error)
    }
  }, [editingOS, isAdminKraflo, profile?.empresa_id])

  useEffect(() => {
    if (open) {
      loadTecnicos()
      if (editingOS) {
        setValue('equipamento_nome', editingOS.equipamento_nome)
        setValue('equipamento_tag', editingOS.equipamento_tag || '')
        setValue('localizacao', editingOS.localizacao || '')
        setValue('tipo_manutencao', (editingOS.tipo_manutencao as any) || undefined)
        setValue('prioridade', (editingOS.prioridade as any) || undefined)
        setValue('descricao_problema', editingOS.descricao_problema || '')
        setValue('diagnostico_solucao', editingOS.diagnostico_solucao || '')
        setValue('notas_finais', editingOS.notas_finais || '')
        setSelectedTecnico(String(editingOS.tecnico_id))
        const validStatuses = [
          'Aberta',
          'Em manutenção',
          'Fechada',
          'Liberado para produção',
          'Não liberado',
        ] as const
        type StatusType = (typeof validStatuses)[number]
        const osStatus = validStatuses.includes(
          editingOS.status_os as StatusType,
        )
          ? (editingOS.status_os as StatusType)
          : 'Aberta'
        setStatus(osStatus)
        if (editingOS.url_foto) {
          setFotoPreview(editingOS.url_foto)
        }
      } else {
        reset()
        setSelectedTecnico('')
        setStatus('Aberta')
        setFoto(null)
        setFotoPreview(null)
        setCategoriaParadaId('')
        setSubcategoriaParadaId('')
        setReincidenciaData(null)
      }
    }
  }, [open, editingOS, loadTecnicos, reset, setValue])

  // Auto-scroll to first error
  useEffect(() => {
    const firstError = Object.keys(errors)[0];
    if (firstError) {
      const element = document.getElementById(firstError);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth', block: 'center' });
        element.focus();
      }
    }
  }, [errors]);

  const onSubmit = async (data: OSFormData) => {
    if (!selectedTecnico) {
      toast.error('Selecione um técnico')
      return
    }

    if (!editingOS && !categoriaParadaId) {
      toast.error('Selecione o motivo de parada')
      return
    }

    setIsLoading(true)
    try {
      const empresaId = editingOS?.empresa_id || profile?.empresa_id
      if (!empresaId && !isAdminKraflo) {
        throw new Error('Empresa não encontrada')
      }

      let urlFoto = editingOS?.url_foto || null

      // Upload foto se existir uma nova
      if (foto) {
        const fileExt = foto.name.split('.').pop()
        const fileName = `abertura_${Date.now()}.${fileExt}`
        const filePath = `${empresaId}/${fileName}`

        const { error: uploadError } = await supabase.storage
          .from('anexos-os')
          .upload(filePath, foto)

        if (uploadError) throw uploadError

        const { data: publicUrl } = supabase.storage
          .from('anexos-os')
          .getPublicUrl(filePath)

        urlFoto = publicUrl.publicUrl
      }

      const osData = {
        equipamento_nome: data.equipamento_nome,
        equipamento_tag: data.equipamento_tag || null,
        localizacao: data.localizacao || null,
        tipo_manutencao: data.tipo_manutencao || null,
        prioridade: data.prioridade || null,
        descricao_problema: data.descricao_problema || null,
        diagnostico_solucao: data.diagnostico_solucao || null,
        notas_finais: data.notas_finais || null,
        tecnico_id: parseInt(selectedTecnico),
        empresa_id: empresaId!,
        status_os: status,
        url_foto: urlFoto,
        categoria_parada_id: categoriaParadaId || null,
        subcategoria_parada_id: subcategoriaParadaId || null,
        data_fechamento:
          status === 'Fechada' || status === 'Liberado para produção'
            ? new Date().toISOString()
            : null,
      }

      if (editingOS) {
        const { error } = await supabase
          .from('ordens_de_servico')
          .update(osData)
          .eq('id', editingOS.id)

        if (error) throw error
        toast.success('OS atualizada com sucesso!')
      } else {
        const { error } = await supabase
          .from('ordens_de_servico')
          .insert([osData])

        if (error) throw error
        toast.success('OS criada com sucesso!')
      }

      onSuccess()
      onClose()
    } catch (error) {
      handleError(error)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto w-[95vw] sm:w-full glass-panel border-white/10 shadow-surface p-6 sm:p-8">
        <DialogHeader className="mb-4">
          <DialogTitle className="text-xl font-display text-primary flex items-center gap-2">
            <span className="h-6 w-1 bg-primary rounded-full"></span>
            {editingOS ? 'Editar Ordem de Serviço' : 'Nova Ordem de Serviço'}
          </DialogTitle>
        </DialogHeader>

        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Equipamento */}
            <div className="space-y-2">
              <Label
                htmlFor="equipamento_nome"
                className="flex items-center gap-1"
              >
                Nome do Equipamento
                <span className="text-destructive">*</span>
              </Label>
              <Input
                id="equipamento_nome"
                {...register('equipamento_nome')}
                placeholder="Ex: Tear Picanol"
              />
              {errors.equipamento_nome && (
                <p className="text-xs text-destructive">
                  {errors.equipamento_nome.message}
                </p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="equipamento_tag">TAG do Equipamento</Label>
              <Input
                id="equipamento_tag"
                {...register('equipamento_tag')}
                placeholder="Ex: TP-001"
                onBlur={(e) => {
                  if (!editingOS) {
                    checkReincidencia(e.target.value)
                  }
                }}
              />
              {checkingReincidencia && (
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Loader2 className="h-3 w-3 animate-spin" />
                  Verificando histórico...
                </p>
              )}
            </div>

            {/* Localização */}
            <div className="space-y-2">
              <Label htmlFor="localizacao">Localização</Label>
              <Input
                id="localizacao"
                {...register('localizacao')}
                placeholder="Ex: Setor A, Linha 3, Galpão 2"
              />
            </div>

            {/* Técnico */}
            <div className="space-y-2">
              <Label className="flex items-center gap-1">
                Técnico Responsável
                <span className="text-destructive">*</span>
              </Label>
              <Select
                value={selectedTecnico}
                onValueChange={setSelectedTecnico}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Selecione o técnico" />
                </SelectTrigger>
                <SelectContent>
                  {tecnicos.map((tecnico) => (
                    <SelectItem
                      key={tecnico.id_telegram}
                      value={String(tecnico.id_telegram)}
                    >
                      {tecnico.nome_completo}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Tipo de Manutenção */}
            <div className="space-y-2">
              <Label className="flex items-center gap-1">
                Tipo de Manutenção
                <span className="text-destructive">*</span>
              </Label>
              <Controller
                control={control}
                name="tipo_manutencao"
                render={({ field }) => (
                  <Select
                    value={field.value}
                    onValueChange={field.onChange}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Selecione o tipo" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="Corretiva">Corretiva</SelectItem>
                      <SelectItem value="Preventiva">Preventiva</SelectItem>
                      <SelectItem value="Preditiva">Preditiva</SelectItem>
                    </SelectContent>
                  </Select>
                )}
              />
              {errors.tipo_manutencao && (
                <p className="text-xs text-destructive">
                  {errors.tipo_manutencao.message}
                </p>
              )}
            </div>

            {/* Prioridade */}
            <div className="space-y-2">
              <Label className="flex items-center gap-1">
                Prioridade
                <span className="text-destructive">*</span>
              </Label>
              <Controller
                control={control}
                name="prioridade"
                render={({ field }) => (
                  <Select
