export function useEquipmentTags(empresaId: string | undefined) {
  return useQuery({
    queryKey: ["equipment-tags", empresaId],
    queryFn: async (): Promise<Array<{ tag: string; nome: string; total: number }>> => {
      if (!empresaId) return [];

      const { data, error } = await supabase
        .from("ordens_de_servico")
        .select("equipamento_tag, equipamento_nome")
        .eq("empresa_id", empresaId)
        .not("equipamento_tag", "is", null);

      if (error) {
        console.error("Error fetching equipment tags:", error);
        throw error;
      }

      // Agrupa por TAG
      const tagMap = new Map<string, { nome: string; total: number }>();
      (data || []).forEach((os) => {
        if (os.equipamento_tag) {
          const existing = tagMap.get(os.equipamento_tag);
          if (existing) {
            existing.total++;
          } else {
            tagMap.set(os.equipamento_tag, {
              nome: os.equipamento_nome,
              total: 1,
            });
          }
        }
      });

      return Array.from(tagMap.entries())
        .map(([tag, info]) => ({ tag, ...info }))
        .sort((a, b) => b.total - a.total);
    },
    enabled: !!empresaId,
  });
}

import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";

export interface TechnicianPerformance {
  tecnico_id: number;
  nome_completo: string;
  empresa_id: string;
  funcao: string | null;
  setor: string | null;
  total_os_fechadas: number;
  mttr_medio_horas: number;
  quality_score: number;
  total_retrabalhos: number;
  os_por_tipo: Record<string, number>;
  os_heroi: Array<{
    os_id: number;
    equipamento_tag: string;
    horas_aberto: number;
    data_fechamento: string;
  }>;
  primeira_os: string | null;
  ultima_os: string | null;
}

export interface TeamMTTRComparison {
  tipo: string;
  meu_mttr: number;
  media_equipe: number;
  diferenca_percentual: number;
}

export function useTechnicianPerformance(empresaId: string | undefined, tecnicoId?: number) {
  return useQuery({
    queryKey: ["technician-performance", empresaId, tecnicoId],
    queryFn: async (): Promise<TechnicianPerformance | null> => {
      if (!empresaId) return null;

      // Query the view directly
      let query = supabase
        .from("v_technician_performance")
        .select("*")
        .eq("empresa_id", empresaId);

      if (tecnicoId) {
        query = query.eq("tecnico_id", tecnicoId);
      }

      const { data, error } = await query.limit(1).single();

      if (error) {
        if (error.code === "PGRST116") {
          // No rows returned
          return null;
        }
        console.error("Error fetching technician performance:", error);
        throw error;
      }

      return {
        ...data,
        os_por_tipo: (data.os_por_tipo as Record<string, number>) || {},
        os_heroi: (data.os_heroi as unknown as TechnicianPerformance["os_heroi"]) || [],
      } as TechnicianPerformance;
    },
    enabled: !!empresaId,
  });
}

